sql:
SELECT AVG(duration) 
FROM fitness_sessions 
WHERE trainer_id = 1;

SELECT AVG(duration) 
FROM fitness_sessions 
WHERE trainer_id = (SELECT user_id FROM user_accounts WHERE username = 'trainer1');

SELECT session_date, AVG(calories_burned) AS average_calories_burned
FROM fitness_sessions
GROUP BY session_date;

SELECT COUNT(DISTINCT participant_id) AS num_participants
FROM fitness_goals
WHERE goal_type = 'Weight Loss';

SELECT participant_id, measurement_date, body_fat, skeletal_muscle_mass
FROM body_metrics
WHERE STRFTIME('%Y', measurement_date) < '2022';

SELECT AVG(rib_bmd), AVG(spine_bmd), AVG(hip_bmd), AVG(body_fat), AVG(skeletal_muscle_mass), AVG(visceral_fat), AVG(water_percentage)
FROM body_metrics
WHERE participant_id = 1;

SELECT session_id, duration
FROM fitness_sessions
ORDER BY duration DESC;

SELECT AVG(fs.duration) AS AverageSessionDuration
FROM fitness_sessions fs
JOIN user_accounts ua ON fs.trainer_id = ua.user_id;

SELECT participant_id
FROM fitness_goals
WHERE current_value = (
    SELECT MAX(current_value) FROM fitness_goals
);

external_knowledge:
; The user_accounts table stores general information about each user, such as user_id, name, email, etc.; 
; The study_participants table contains records of user participation in research studies, linked to the user_accounts table by user_id; 
; The access_logs table is not directly relevant to the question but is joined to filter user_ids if needed.

